# create_dataset.py
# Loads the Iris dataset, adds a synthetic 4th class 'iris-fake' generated by AI,
# saves the combined dataset to CSV and creates a 4-class scatter plot.

import numpy as np
import pandas as pd
import matplotlib.pyplot as plt
from sklearn.datasets import load_iris

# ─── 1. Load the original Iris dataset (150 samples, 3 classes) ──────────────
iris = load_iris()
X_real = iris.data        # shape (150, 4)
y_real = iris.target      # 0=setosa, 1=versicolor, 2=virginica
class_names_real = iris.target_names  # ['setosa', 'versicolor', 'virginica']

# ─── 2. Generate 50 synthetic samples for 'iris-fake' (class 3) ──────────────
# Feature values = average of the 3 real classes + Gaussian noise
rng = np.random.default_rng(seed=42)
mean_features = X_real.mean(axis=0)           # mean of all 150 real samples
std_features  = X_real.std(axis=0) * 0.5      # half the real std as noise scale

X_fake = rng.normal(loc=mean_features, scale=std_features, size=(50, 4))
X_fake = np.clip(X_fake, 0.1, None)           # no negative measurements

# ─── 3. Combine real + synthetic data ────────────────────────────────────────
X_all = np.vstack([X_real, X_fake])
y_all = np.concatenate([y_real, np.full(50, 3, dtype=int)])  # label 3 = iris-fake

species_names = ['setosa', 'versicolor', 'virginica', 'iris-fake']
species_labels = [species_names[i] for i in y_all]

# ─── 4. Save to CSV (200 rows, 5 columns) ────────────────────────────────────
df = pd.DataFrame(X_all, columns=['sepal_length', 'sepal_width', 'petal_length', 'petal_width'])
df['species'] = species_labels

df.to_csv('dataset.csv', index=False)
print(f"Saved: dataset.csv  ({len(df)} rows, {len(df.columns)} columns)")
print(f"  Class counts: { {name: (df['species'] == name).sum() for name in species_names} }")

# ─── 5. Scatter plot: petal_length vs petal_width, colored by species ────────
colors  = ['#e74c3c', '#2ecc71', '#3498db', '#9b59b6']  # red, green, blue, purple
markers = ['o', 's', '^', 'D']
labels  = ['Setosa', 'Versicolor', 'Virginica', 'Iris-Fake (AI)']

fig, ax = plt.subplots(figsize=(8, 6))

for i, (color, marker, label) in enumerate(zip(colors, markers, labels)):
    mask = y_all == i
    ax.scatter(
        X_all[mask, 2],   # petal_length
        X_all[mask, 3],   # petal_width
        c=color,
        marker=marker,
        label=label,
        edgecolors='white',
        linewidths=0.5,
        s=70,
        alpha=0.85
    )

ax.set_title('Iris Dataset - Petal Length vs Petal Width\n(including AI-generated iris-fake class)',
             fontsize=12, fontweight='bold')
ax.set_xlabel('Petal Length (cm)')
ax.set_ylabel('Petal Width (cm)')
ax.legend(title='Species')
ax.grid(True, linestyle='--', alpha=0.4)

plt.tight_layout()
plt.savefig('dataset_plot.png', dpi=150)
plt.close()
print("Saved: dataset_plot.png")
